#!/usr/bin/env sage
"""
Find an explicit conjugating permutation between two natural degree-27 actions of the
order-1296 group:

  (1) the stabilizer of a point v0 in Aut(W33) acting on H27 = non-neighbors(v0),
  (2) the automorphism group of the firewall-effective 36 triads acting on the 27 Schläfli labels.

This produces a concrete identification:
  H27_local_index (0..26)  <->  Schläfli E6-id label (0..26)

Writes:
  artifacts/sage_h27_to_schlafli_effective_triads_conjugacy.json
"""


# This file was *autogenerated* from the file tools/sage_conjugacy_h27_to_schlafli_effective_triads.sage
from sage.all_cmdline import *  # import sage library

_sage_const_1 = Integer(1)
_sage_const_27 = Integer(27)
_sage_const_0 = Integer(0)
_sage_const_2 = Integer(2)
_sage_const_3 = Integer(3)
_sage_const_4 = Integer(4)
_sage_const_40 = Integer(40)
_sage_const_36 = Integer(36)
_sage_const_1296 = Integer(1296)
_sage_const_51840 = Integer(51840)
_sage_const_28 = Integer(28)
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[_sage_const_1]
OUT = ROOT / "artifacts" / "sage_h27_to_schlafli_effective_triads_conjugacy.json"


def triad_key(t):
    a, b, c = (int(x) for x in t)
    return tuple(sorted((a, b, c)))


def build_incidence_graph(triads):
    V = [("v", i) for i in range(_sage_const_27)]
    T = [("t", k) for k in range(len(triads))]
    G = Graph()
    G.add_vertices(V)
    G.add_vertices(T)
    for k, (a, b, c) in enumerate(triads):
        tk = ("t", k)
        G.add_edge(("v", int(a)), tk)
        G.add_edge(("v", int(b)), tk)
        G.add_edge(("v", int(c)), tk)
    return G, V, T


def induced_action_on_V(aut, V):
    gens = []
    for g in aut.gens():
        perm = []
        for i in range(_sage_const_27):
            img = g(("v", i))
            if img[_sage_const_0] != "v":
                raise RuntimeError("Partition-violating automorphism")
            perm.append(int(img[_sage_const_1]) + _sage_const_1)  # 1-based
        gens.append(Permutation(perm))
    return PermutationGroup(gens)


def symp(u, v):
    return (
        u[_sage_const_0] * v[_sage_const_2]
        + u[_sage_const_1] * v[_sage_const_3]
        - u[_sage_const_2] * v[_sage_const_0]
        - u[_sage_const_3] * v[_sage_const_1]
    )


def w33_graph_and_aut():
    # Match the repo's Python ordering in tools/compute_double_sixes.py:build_w33_f3().
    pts = []
    seen = set()
    for a in (_sage_const_0, _sage_const_1, _sage_const_2):
        for b in (_sage_const_0, _sage_const_1, _sage_const_2):
            for c in (_sage_const_0, _sage_const_1, _sage_const_2):
                for d in (_sage_const_0, _sage_const_1, _sage_const_2):
                    if (a, b, c, d) == (
                        _sage_const_0,
                        _sage_const_0,
                        _sage_const_0,
                        _sage_const_0,
                    ):
                        continue
                    v = [a, b, c, d]
                    for i in range(_sage_const_4):
                        if v[i] != _sage_const_0:
                            inv = (
                                _sage_const_1
                                if v[i] == _sage_const_1
                                else _sage_const_2
                            )  # inverse mod 3
                            v = [(x * inv) % _sage_const_3 for x in v]
                            break
                    t = tuple(v)
                    if t not in seen:
                        seen.add(t)
                        pts.append(t)
    if len(pts) != _sage_const_40:
        raise RuntimeError("Expected 40 projective points")

    idx = {p: i for i, p in enumerate(pts)}
    G = Graph()
    G.add_vertices(range(_sage_const_40))
    for i in range(_sage_const_40):
        for j in range(i + _sage_const_1, _sage_const_40):
            if symp(pts[i], pts[j]) % _sage_const_3 == _sage_const_0:
                G.add_edge(i, j)
    aut = G.automorphism_group()
    return pts, idx, G, aut


def restrict_to_subset(G, subset):
    # Restrict a permutation group G acting on 40 points (0..39) to a subset list of size 27.
    subset = list(subset)
    pos = {subset[i]: i for i in range(len(subset))}
    gens = []
    for g in G.gens():
        perm = []
        for x in subset:
            y = g(x)
            perm.append(pos[int(y)] + _sage_const_1)  # 1-based
        gens.append(Permutation(perm))
    return PermutationGroup(gens)


def find_normal_27(G):
    for N in G.normal_subgroups():
        if int(N.order()) == _sage_const_27:
            return N
    raise RuntimeError("No normal subgroup of order 27 found")


def regular_element_to_point_map(N, base_pt):
    # N has order 27 acting regularly on 27 points.
    mapping = {}
    for n in N:
        mapping[int(n(base_pt))] = n
    if len(mapping) != _sage_const_27:
        raise RuntimeError("Normal 27-subgroup did not act regularly")
    return mapping


def main():
    # --- Build effective-triad automorphism group on Schläfli labels 0..26.
    canon = json.loads(
        (ROOT / "artifacts" / "canonical_su3_gauge_and_cubic.json").read_text(
            encoding="utf-8"
        )
    )
    tri45 = sorted({triad_key(t["triple"]) for t in canon["solution"]["d_triples"]})
    fw = json.loads(
        (ROOT / "artifacts" / "firewall_bad_triads_mapping.json").read_text(
            encoding="utf-8"
        )
    )
    bad9 = sorted({triad_key(t) for t in fw["bad_triangles_Schlafli_e6id"]})
    tri36 = sorted(set(tri45) - set(bad9))
    if len(tri36) != _sage_const_36:
        raise RuntimeError("Expected 36 effective triads")

    Hgraph, Vpart, Tpart = build_incidence_graph(tri36)
    aut_eff = Hgraph.automorphism_group(partition=[Vpart, Tpart])
    G_eff = induced_action_on_V(aut_eff, Vpart)
    if int(G_eff.order()) != _sage_const_1296:
        raise RuntimeError("Expected aut(effective triads) order 1296")

    # --- Build W33, take point stabilizer, restrict to H27.
    pts, idx, G_w33, AutW33 = w33_graph_and_aut()
    if int(AutW33.order()) != _sage_const_51840:
        raise RuntimeError("Expected |Aut(W33)|=51840")
    v0 = _sage_const_0
    Stab = AutW33.stabilizer(v0)
    if int(Stab.order()) != _sage_const_1296:
        raise RuntimeError("Expected point stabilizer order 1296")

    # H27 = non-neighbors of v0 (excluding v0).
    H12 = set(G_w33.neighbors(v0))
    H27 = sorted(set(range(_sage_const_40)) - H12 - set([v0]))
    if len(H27) != _sage_const_27:
        raise RuntimeError("Expected |H27|=27")

    G_h27 = restrict_to_subset(Stab, H27)
    if int(G_h27.order()) != _sage_const_1296:
        raise RuntimeError("Restricted group unexpectedly changed order")

    # --- Identify conjugacy via the normal regular subgroup of order 27.
    N_eff = find_normal_27(G_eff)
    N_h27 = find_normal_27(G_h27)

    # We need a permutation isomorphism (conjugacy in Sym(27)) between the two actions.
    # Both groups have a normal regular subgroup N of order 27, but the isomorphism between
    # N_h27 and N_eff is not unique. We brute over Aut(N_eff) to find a compatible one.

    iso0 = N_h27.isomorphism_to(N_eff)

    base = _sage_const_1  # 1-based point index in both actions
    map_h27 = regular_element_to_point_map(N_h27, base)

    Sym = SymmetricGroup(_sage_const_27)
    G_eff_S = PermutationGroup([Sym(g) for g in G_eff.gens()])
    found = False
    p_list = None
    p = None
    # Search over (basepoint image) × (conjugation inside G_eff_S) to realize a conjugacy.
    # Total trials = 27 * 1296 = 34992, feasible.
    for y0 in range(_sage_const_1, _sage_const_28):
        for s in G_eff_S:
            trial = []
            for x in range(_sage_const_1, _sage_const_28):
                n_x = map_h27[x]
                m2 = s.inverse() * iso0(n_x) * s
                trial.append(int(m2(y0)))
            p_trial = Sym(trial)

            ok = True
            for g in G_h27.gens():
                conj = p_trial.inverse() * Sym(g) * p_trial
                if not (conj in G_eff_S):
                    ok = False
                    break
            if ok:
                found = True
                p_list = trial
                p = p_trial
                break
        if found:
            break

    if not found:
        raise RuntimeError(
            "No conjugating permutation found (actions may be non-conjugate)"
        )

    # Convert to 0-based mapping from H27 local index -> Schläfli label.
    # In G_h27, point i (1-based) corresponds to H27[i-1] global W33 vertex.
    # In G_eff, point j (1-based) corresponds to Schläfli label (j-1).
    h27_local_to_schlafli = [
        int(p(i + _sage_const_1)) - _sage_const_1 for i in range(_sage_const_27)
    ]

    out = {
        "status": "ok",
        "w33": {
            "v0": int(v0),
            "H27_global": [int(x) for x in H27],
        },
        "groups": {
            "order": int(_sage_const_1296),
            "structure_eff": str(G_eff.structure_description()),
            "structure_h27": str(G_h27.structure_description()),
            "structure_normal27": str(N_eff.structure_description()),
        },
        "conjugating_perm_1based": list(map(int, p_list)),
        "h27_local_to_schlafli_e6id": h27_local_to_schlafli,
    }

    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text(
        json.dumps(out, indent=_sage_const_2, sort_keys=True, default=lambda x: int(x))
        + "\n",
        encoding="utf-8",
    )
    print("status=ok wrote", OUT)


if __name__ == "__main__":
    main()
